								WHEN unique_violation THEN
									GET STACKED DIAGNOSTICS
										returned_state = RETURNED_SQLSTATE,
										message = MESSAGE_TEXT;
									INSERT INTO do_native_sqlstate_seen VALUES (
										returned_state,
										(length(message) > 0)::text
									);
							END;
						END;
					$$;

