					RETURN total;
				END;
				$$ LANGUAGE plpgsql;

CREATE FUNCTION plpgsql_foreach_slice_sum(values_in INT[])
				RETURNS INT AS $$
				DECLARE
					row_slice INT[];
					value_seen INT;
					total INT := 0;
				BEGIN
					FOREACH row_slice SLICE 1 IN ARRAY values_in LOOP
						FOREACH value_seen IN ARRAY row_slice LOOP
